  ('dietitian-moex-10034', 'dietitian', 'dietitian-moex-095-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '某學校的營養午餐預計供應1000人用餐，每人每餐繳交45元，一個月供應20餐，扣掉老闆利潤10％，人事費30％ ，固定水電費20％，每月用來採購食物的費用約多少元？', '["120,000", "240,000", "360,000", "480,000"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:55+00:00", "source_pdf_sha1": "7b390a71e901", "answer_pdf_sha1": "f2264178b21a", "source_family": "moex-gov-tw", "moex": {"exam_code": "095030", "c": "112", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "095", "exam_name": "095年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 2, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
